  (1000, 'What is the Heisenberg Uncertainty Principle?',                                           'You cannot simultaneously know both the exact position and exact momentum of a particle'),
  (1000, 'What phenomenon causes a straw to appear bent in a glass of water?',                      'Refraction'),
  (1000, 'What protein carries oxygen in red blood cells?',                                         'Hemoglobin'),
  (1000, 'In DNA, which base pairs with adenine?',                                                  'Thymine'),
  (1000, 'What is the name of the boundary between Earth''s mantle and outer core?',                'The Gutenberg discontinuity'),
