  (1200, 'What law states that the entropy of a perfect crystal at absolute zero is exactly zero?',  'The Third Law of Thermodynamics'),
  (1200, 'What is the name of the point inside a black hole where density becomes infinite?',       'The singularity'),
  (1200, 'What is the difference between a sigma bond and a pi bond?',                              'Sigma bonds form by head-on orbital overlap; pi bonds form by side-to-side orbital overlap'),
  (1200, 'What is the P vs NP problem in computer science?',                                        'Whether every problem whose solution can be quickly verified can also be quickly solved')
