  (1000, 'What is rendering in cooking?',                                                         'Slowly melting and extracting fat from meat or fat tissue over low heat'),
  (1000, 'What is the Scoville scale used for?',                                                  'Measuring the heat of chilli peppers and spicy foods by quantifying capsaicin concentration'),
  (1000, 'What is koji in Japanese food fermentation?',                                           'The mould Aspergillus oryzae, used to ferment miso, sake, soy sauce, and mirin'),
  (1000, 'What is Parmigiano-Reggiano and where must it be produced?',                           'Italian hard cheese aged at least 12 months, legally protected and produced only in Parma, Reggio Emilia, and surrounding areas'),
  (1000, 'What is mise en place?',                                                                'French culinary concept meaning "everything in its place" — preparing and organising ingredients before cooking'),
  (1200, 'What enzymatic reaction makes a cut apple turn brown?',                                'Oxidation (enzymatic browning) catalysed by polyphenol oxidase reacting with oxygen'),
  (1200, 'What is transglutaminase and how is it used in cooking?',                              'An enzyme ("meat glue") that bonds proteins together — used in modernist cuisine to combine proteins'),
  (1200, 'At approximately what temperature (Celsius) does the Maillard reaction occur?',        'Approximately 140–165°C (284–329°F)'),
  (1200, 'What is the difference between kefir and yogurt?',                                     'Kefir uses bacteria and yeast (kefir grains), producing a thinner, slightly fizzy drink; yogurt uses only bacteria'),
  (1200, 'What is escabeche?',                                                                    'A Mediterranean/Latin American technique of marinating cooked fish or meat in vinegar and spices'),
  (1200, 'How does acid make meat more tender when used in a marinade?',                         'Acid denaturation — it breaks down protein structures (collagen and muscle fibres), softening texture'),
  (1200, 'What is the French cooking term suer and what does it mean?',                          'To sweat — gently cooking aromatics in butter over low heat until soft without browning'),
  (1200, 'What is tataki in Japanese cooking?',                                                   'Lightly searing fish or meat on the outside while leaving it raw inside, then slicing thinly')
) AS q(pts, q_en, a_en)
WHERE c.name_en = 'Food & Drink';

