-- 13. POLITICS (50 questions)
INSERT INTO questions (category_id, points, question_en, answer_en, question_ar, answer_ar)
SELECT c.id, q.pts, q.q_en, q.a_en, '', ''
FROM categories c
CROSS JOIN (VALUES
  (200,  'How many permanent members does the UN Security Council have?',                         'Five permanent members'),
  (200,  'What does NATO stand for?',                                                             'North Atlantic Treaty Organization'),
  (200,  'What is a democracy?',                                                                  'A system of government where power belongs to the people, typically through elected representatives'),
  (200,  'What does OPEC stand for?',                                                             'Organization of the Petroleum Exporting Countries'),
  (200,  'What is the capital city of the United States?',                                        'Washington, D.C.'),
  (200,  'What is the governing document of the United States called?',                           'The Constitution'),
  (200,  'How many countries are members of the United Nations approximately?',                  '193 member states'),
  (200,  'What is the US legislative body that makes laws called?',                               'Congress (Senate and House of Representatives)'),
  (200,  'What is a dictatorship?',                                                               'A political system run by one person or group with absolute power'),
  (400,  'What political system divides power between central and regional governments?',         'Federalism'),
  (400,  'In what year was the Universal Declaration of Human Rights adopted by the UN?',        '1948'),
  (400,  'What building is where the US Congress meets?',                                         'The United States Capitol Building'),
  (400,  'What is the difference between a republic and a direct democracy?',                    'A republic uses elected representatives; a direct democracy has citizens vote directly on all laws'),
  (400,  'What is the UK legislative body called?',                                               'Parliament (House of Commons and House of Lords)'),
  (400,  'What is a formal agreement between two or more countries called?',                     'A treaty'),
  (400,  'Who was the first leader of the Soviet Union?',                                         'Vladimir Lenin'),
  (400,  'What is the judicial branch of government?',                                            'The branch that interprets laws and administers justice'),
  (400,  'What country has the world''s oldest Parliament (the Althing, founded 930 AD)?',       'Iceland'),
  (600,  'Who was the first Secretary-General of the United Nations?',                           'Trygve Lie (Norway)'),
  (600,  'What Latin term means past court decisions must be followed in similar future cases?',  'Stare decisis'),
  (600,  'What is proportional representation in electoral systems?',                             'A system where the percentage of legislative seats matches the percentage of votes a party receives'),
  (600,  'What is the difference between parliamentary and presidential government systems?',    'Parliamentary: the executive comes from the legislature; Presidential: the executive is separately elected'),
  (600,  'What is veto power in the UN Security Council?',                                        'The ability of any permanent member to block a resolution by voting against it'),
  (600,  'What is the founding treaty of the European Union?',                                   'The Treaty of Maastricht (1992)'),
  (600,  'What is gerrymandering?',                                                               'Manipulating electoral district boundaries to give one political party an unfair advantage'),
  (600,  'What political theory did Karl Marx develop?',                                          'Marxism (or scientific socialism / historical materialism)'),
  (800,  'What is the social contract theory in political philosophy?',                          'Individuals give up some freedoms to a governing authority in exchange for protection of their remaining rights'),
  (800,  'What is the Westphalian system in international relations?',                           'The system of sovereign nation-states recognising each other''s right to rule without external interference'),
  (800,  'What is the democratic peace theory?',                                                  'The observation that democratic countries rarely go to war with each other'),
  (800,  'What is soft power in international relations?',                                        'Influence achieved through attraction, culture, and values rather than military or economic coercion'),
  (800,  'What is habeas corpus?',                                                                'The legal right requiring someone arrested to be brought before a judge — protecting against unlawful detention'),
  (800,  'What is judicial review in the United States?',                                         'The power of the Supreme Court to declare laws unconstitutional — established by Marbury v. Madison (1803)'),
  (800,  'What is the UN Responsibility to Protect (R2P) doctrine?',                             'The principle that states must protect citizens from mass atrocities, and the international community may intervene if they fail'),
  (800,  'What is nationalism as a political doctrine?',                                          'The belief that people sharing a national identity should govern themselves in their own independent state'),
  (1000, 'What is the Overton Window in political science?',                                      'The range of policies the public currently considers acceptable — ideas outside it are seen as radical'),
  (1000, 'What is the prisoners'' dilemma and its relevance to politics?',                        'A game theory scenario where self-interest leads to worse outcomes for both parties than cooperation would — illustrating why international cooperation is difficult'),
  (1000, 'What is the difference between de jure and de facto sovereignty?',                     'De jure is legally recognised sovereignty; de facto is actual control regardless of legal recognition'),
  (1000, 'What is the realist school of thought in international relations?',                    'States act in self-interest in an anarchic system; power and security are the primary drivers of behaviour'),
  (1000, 'What is the Treaty on the Non-Proliferation of Nuclear Weapons (NPT)?',               'An international treaty preventing spread of nuclear weapons, promoting disarmament and peaceful nuclear use'),
  (1000, 'What is multilateralism in international relations?',                                   'The coordination of foreign policy among multiple countries, often through international institutions'),
  (1000, 'What is lobbying and why is it controversial?',                                         'Organised effort to influence government decisions; controversial because wealthy groups may gain disproportionate political power'),
  (1000, 'What is liberal institutionalism in international relations?',                          'The theory that international institutions and cooperation can overcome anarchy and promote peace'),
  (1200, 'What is Arrow''s Impossibility Theorem?',                                               'No ranked voting system can simultaneously satisfy all "fair" criteria when there are three or more candidates'),
  (1200, 'What is the difference between deontological and consequentialist ethics?',            'Deontological ethics judges by adherence to rules/duties; consequentialist ethics judges by outcomes'),
  (1200, 'What is the Gini coefficient used to measure?',                                         'Income or wealth inequality — 0 is perfect equality, 1 (or 100%) is maximum inequality'),
  (1200, 'What is subsidiarity in EU law?',                                                       'Decisions should be made at the most local level possible; higher levels intervene only when necessary'),
  (1200, 'What are Max Weber''s three types of political authority?',                              'Traditional (custom), charismatic (personal qualities), and rational-legal (rules and laws)'),
  (1200, 'What is popular sovereignty?',                                                          'The principle that government authority is derived from and legitimised by the consent of the governed'),
  (1200, 'What are the three pillars of the UN Responsibility to Protect doctrine?',              '1) State responsibility; 2) International assistance; 3) International intervention when states manifestly fail'),
  (1200, 'Who wrote A Theory of Justice (1971), reviving liberal political philosophy?',          'John Rawls')
) AS q(pts, q_en, a_en)
WHERE c.name_en = 'Politics';

-- Done! Run a quick sanity check:
SELECT c.name_en, COUNT(q.id) as question_count
FROM categories c
LEFT JOIN questions q ON q.category_id = c.id
GROUP BY c.name_en
ORDER BY c.name_en;
